{"path": "frontend/src/store/useStore.ts", "content": "import { create } from 'zustand'

export interface Message {
  id: string
  role: 'user' | 'assistant' | 'system'
  content: string
  timestamp: Date
}

export interface Task {
  id: string
  title: string
  status: 'pending' | 'in_progress' | 'completed'
  assignee?: string
}

interface AppState {
  messages: Message[]
  tasks: Task[]
  isConnected: boolean

  addMessage: (message: Message) => void
  updateTask: (id: string, status: Task['status']) => void
  setConnection: (connected: boolean) => void
}

export const useStore = create<AppState>((set) => ({
  messages: [],
  tasks: [],
  isConnected: false,

  addMessage: (message) => set((state) => ({
    messages: [...state.messages, message]
  })),

  updateTask: (id, status) => set((state) => ({
    tasks: state.tasks.map(t => t.id === id ? { ...t, status } : t)
  })),

  setConnection: (isConnected) => set({ isConnected })
}))
"}

{"path": "frontend/src/api/client.ts", "content": "const API_BASE = import.meta.env.VITE_API_URL || 'http://localhost:8000';

export interface ApiMessage {
  role: 'user' | 'assistant' | 'system';
  content: string;
}

export class ApiClient {
  async chat(messages: ApiMessage[]): Promise<string> {
    const response = await fetch(`${API_BASE}/api/chat`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ messages })
    });
    if (!response.ok) throw new Error(`API Error: ${response.status}`);
    const data = await response.json();
    return data.response;
  }

  async getHealth(): Promise<boolean> {
    try {
      const response = await fetch(`${API_BASE}/health`);
      return response.ok;
    } catch {
      return false;
    }
  }
}

export const apiClient = new ApiClient();
"}

{"path": "frontend/src/utils/formatters.ts", "content": "export function formatTime(date: Date): string {
  return new Intl.DateTimeFormat('zh-CN', {
    hour: '2-digit',
    minute: '2-digit'
  }).format(date);
}

export function formatRelativeTime(date: Date): string {
  const now = new Date();
  const diff = now.getTime() - date.getTime();
  const minutes = Math.floor(diff / 60000);

  if (minutes < 1) return '刚刚';
  if (minutes < 60) return `${minutes}分钟前`;
  if (minutes < 1440) return `${Math.floor(minutes / 60)}小时前`;
  return `${Math.floor(minutes / 1440)}天前`;
}
"}

{"path": "frontend/src/hooks/useDebounce.ts", "content": "import { useState, useEffect } from 'react';

export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}
"}

{"path": "frontend/src/hooks/useTypewriter.ts", "content": "import { useState, useEffect } from 'react';

export function useTypewriter(text: string, speed = 30) {
  const [displayed, setDisplayed] = useState('');
  const [isComplete, setIsComplete] = useState(false);

  useEffect(() => {
    setDisplayed('');
    setIsComplete(false);

    let index = 0;
    const interval = setInterval(() => {
      if (index < text.length) {
        setDisplayed((prev) => prev + text[index]);
        index++;
      } else {
        clearInterval(interval);
        setIsComplete(true);
      }
    }, speed);

    return () => clearInterval(interval);
  }, [text, speed]);

  return { displayed, isComplete };
}
"}

