{"path": "frontend/src/services/sseClient.ts", "content": "export interface SSEHandlers {
  onConnected?: () => void;
  onMessage?: (data: unknown) => void;
  onError?: (error: Event) => void;
}

export function createSSEClient(url: string, handlers: SSEHandlers): () => void {
  const eventSource = new EventSource(url);

  eventSource.addEventListener('open', () => {
    handlers.onConnected?.();
  });

  eventSource.addEventListener('error', (error) => {
    handlers.onError?.(error as Event);
    eventSource.close();
  });

  eventSource.addEventListener('message', (event: MessageEvent) => {
    try {
      const data = JSON.parse(event.data);
      handlers.onMessage?.(data);
    } catch (e) {
      console.error('Failed to parse SSE message:', e);
    }
  });

  return () => {
    eventSource.close();
  };
}
"}

{"path": "frontend/src/services/sseService.ts", "content": "import { SSEEvent } from '../types';

export class SSEService {
  private eventSource: EventSource | null = null;
  private listeners: Map<string, Set<(data: unknown) => void>> = new Map();

  connect(url: string): void {
    if (this.eventSource) {
      this.disconnect();
    }

    this.eventSource = new EventSource(url);

    this.eventSource.addEventListener('open', () => {
      console.log('SSE connected');
    });

    this.eventSource.addEventListener('error', () => {
      console.error('SSE error');
    });

    this.eventSource.addEventListener('message', (event: MessageEvent) => {
      try {
        const data = JSON.parse(event.data) as SSEEvent;
        this.notifyListeners(data);
      } catch (e) {
        console.error('Failed to parse SSE message:', e);
      }
    });
  }

  disconnect(): void {
    if (this.eventSource) {
      this.eventSource.close();
      this.eventSource = null;
    }
  }

  subscribe(eventType: string, callback: (data: unknown) => void): () => void {
    if (!this.listeners.has(eventType)) {
      this.listeners.set(eventType, new Set());
    }
    this.listeners.get(eventType)!.add(callback);

    return () => {
      this.listeners.get(eventType)?.delete(callback);
    };
  }

  private notifyListeners(event: SSEEvent): void {
    const listeners = this.listeners.get(event.type);
    if (listeners) {
      listeners.forEach(callback => callback(event.data));
    }
  }
}

export const sseService = new SSEService();
"}

