          updateLastMessage(event.data as string);
          break;
        case 'done':
          setStreaming(false);
          break;
        case 'error':
          console.error('SSE error:', event.data);
          setStreaming(false);
          break;
      }
    });

    return () => {
      sseService.disconnect();
    };
  }, [updateLastMessage, setStreaming]);

  const handleSend = () => {
    if (!input.trim() || isStreaming) return;

    // 添加用户消息
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now(),
    };
