        return <Badge variant="outline">已完成</Badge>;
    }
  };

  return (
    <Card className="hover:shadow-md transition-shadow">
      <CardHeader className="pb-2">
        <div className="flex items-start justify-between gap-2">
          <CardTitle className="text-sm font-medium line-clamp-2 flex-1">
            {task.subject}
          </CardTitle>
          {getStatusBadge()}
        </div>
      </CardHeader>
      <CardContent>
        {task.description && (
          <p className="text-xs text-muted-foreground mb-2 line-clamp-3">
            {task.description}
          </p>
        )}

        {task.requiredRole && (
          <div className="flex items-center gap-1 text-xs text-muted-foreground mb-2">
            <span>🔒</span>
            <span>需要: {task.requiredRole}</span>
          </div>
        )}

        {task.owner && (
          <div className="flex items-center gap-1 text-xs text-muted-foreground mb-2">
            <span>👤</span>
            <span>负责人: {task.owner}</span>
          </div>
        )}

        {task.blockedBy && task.blockedBy.length > 0 && (
          <div className="text-xs text-muted-foreground">
            依赖: {task.blockedBy.join(', ')}
          </div>
        )}

        {isClaimable && (
          <div className="mt-3 pt-2 border-t">
            <Button 
              size="sm" 
              className="w-full"
              onClick={() => onClaim?.(task.id)}
            >
              认领任务
            </Button>
          </div>
        )}
      </CardContent>
    </Card>
  );
}
"}

{"path": "frontend/src/components/ui/dropdown-menu.tsx", "content": "import * as React from 'react';

export interface DropdownMenuProps {
  children: React.ReactNode;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}

export const DropdownMenuContext = React.createContext<{
  open: boolean;
  setOpen: (open: boolean) => void;
}>({ open: false, setOpen: () => {} });

export const DropdownMenu: React.FC<DropdownMenuProps> = ({ children, open = false, onOpenChange }) => {
  const [internalOpen, setInternalOpen] = React.useState(open);

  const handleOpenChange = (newOpen: boolean) => {
    setInternalOpen(newOpen);
    onOpenChange?.(newOpen);
  };

  return (
    <DropdownMenuContext.Provider value={{ open: internalOpen, setOpen: handleOpenChange }}>
      <div className="relative">{children}</div>
    </DropdownMenuContext.Provider>
  );
};

export const DropdownMenuTrigger = React.forwardRef<
  HTMLButtonElement,
  React.ButtonHTMLAttributes<HTMLButtonElement>
>(({ children, className = '', onClick, ...props }, ref) => {
  const { setOpen } = React.useContext(DropdownMenuContext);

  return (
    <button
      ref={ref}
      className={className}
      onClick={() => { setOpen(true); onClick?.(); }}
      {...props}
    >
      {children}
    </button>
  );
});
DropdownMenuTrigger.displayName = 'DropdownMenuTrigger';

export const DropdownMenuContent = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ children, className = '', ...props }, ref) => {
  const { open, setOpen } = React.useContext(DropdownMenuContext);

  if (!open) return null;

  return (
    <div
      ref={ref}
      className={`absolute right-0 top-full mt-2 min-w-[8rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md z-50 ${className}`}
      {...props}
    >
      {children}
    </div>
  );
});
DropdownMenuContent.displayName = 'DropdownMenuContent';

export const DropdownMenuItem = React.forwardRef<
  HTMLButtonElement,
  React.ButtonHTMLAttributes<HTMLButtonElement>
>(({ children, className = '', onClick, ...props }, ref) => (
  <button
    ref={ref}
    className={`relative flex w-full cursor-default select-none items-center rounded-sm px-2 py-1.5 text-sm outline-none hover:bg-accent focus:bg-accent ${className}`}
    onClick={(e) => { onClick?.(e); }}
    {...props}
  >
    {children}
  </button>
));
DropdownMenuItem.displayName = 'DropdownMenuItem';
"}

{"path": "frontend/src/services/websocketClient.ts", "content": "import { WSMessage, WSMessageType } from '../types/ws';

export interface WSHandlers {
  onMessage?: (message: WSMessage) => void;
  onError?: (error: Event) => void;
  onClose?: () => void;
}

export function createWSClient(url: string, handlers: WSHandlers): () => void {
  const ws = new WebSocket(url);

  ws.onopen = () => {
    console.log('WebSocket connected');
  };

  ws.onmessage = (event) => {
    try {
      const message: WSMessage = JSON.parse(event.data);
      handlers.onMessage?.(message);
    } catch (e) {
      console.error('Failed to parse WS message:', e);
    }
  };

  ws.onerror = (error) => {
    handlers.onError?.(error);
  };

  ws.onclose = () => {
    handlers.onClose?.();
  };

  return () => {
    ws.close();
  };
}
"}

{"path": "frontend/src/services/websocketService.ts", "content": "import { WSMessage as WSMessageType, MessagePayload, TaskPayload, ProtocolPayload } from '../types/ws';

export class WebSocketService {
  private ws: WebSocket | null = null;
  private listeners: Map<WSMessageType['type'], Set<(data: unknown) => void>> = new Map();

  connect(url: string): void {
    if (this.ws) {
      this.disconnect();
    }

    this.ws = new WebSocket(url);

    this.ws.onopen = () => {
      console.log('WebSocket connected');
    };

    this.ws.onmessage = (event: MessageEvent) => {
      try {
        const message: WSMessageType = JSON.parse(event.data);
        this.notifyListeners(message);
      } catch (e) {
        console.error('Failed to parse WS message:', e);
      }
    };

    this.ws.onerror = (error) => {
      console.error('WebSocket error:', error);
    };
  }

  disconnect(): void {
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
  }

  send(type: string, data?: unknown): void {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify({ type, data }));
    }
  }

  subscribe(eventType: string, callback: (data: unknown) => void): () => void {
    if (!this.listeners.has(eventType)) {
      this.listeners.set(eventType, new Set());
    }
    this.listeners.get(eventType)!.add(callback);

    return () => {
      this.listeners.get(eventType)?.delete(callback);
    };
  }

  private notifyListeners(message: WSMessageType): void {
    const listeners = this.listeners.get(message.type);
    if (listeners) {
      listeners.forEach(callback => callback(message.data));
    }
  }
}

export const wsService = new WebSocketService();
"}

{"path": "frontend/src/stores/chatStore.ts", "content": "import { create } from 'zustand';
import { Message } from '../types';

interface ConnectionInfo {
  status: 'connected' | 'disconnected' | 'connecting';
  lastSeen: number;
}

interface ChatState {
  messages: Message[];
  isStreaming: boolean;
  connection: ConnectionInfo;

  addMessage: (message: Message) => void;
  updateLastMessage: (content: string) => void;
  setStreaming: (streaming: boolean) => void;
  setConnection: (status: ConnectionInfo['status']) => void;
  clearMessages: () => void;
}

export const useChatStore = create<ChatState>((set, get) => ({
  messages: [],
  isStreaming: false,
  connection: {
    status: 'disconnected',
    lastSeen: 0,
  },

  addMessage: (message) => set((state) => ({
    messages: [...state.messages, message]
  })),

  updateLastMessage: (content) => set((state) => {
    const messages = [...state.messages];
    if (messages.length > 0) {
      messages[messages.length - 1] = {
        ...messages[messages.length - 1],
        content: messages[messages.length - 1].content + content
      };
    }
    return { messages };
  }),

  setStreaming: (isStreaming) => set({ isStreaming }),

  setConnection: (status) => set((state) => ({
    connection: {
      status,
      lastSeen: Date.now()
    }
  })),

  clearMessages: () => set({ messages: [] })
}));
"}

{"path": "frontend/src/stores/taskStore.ts", "content": "import { create } from 'zustand';
import { Task } from '../types';

interface TaskGraph {
  tasks: Task[];
  ready: Task[];
  inProgress: Task[];
  completed: Task[];
}

interface TaskStore {
  graph: TaskGraph;
  isLoading: boolean;
  error: string | null;

  fetchTasks: () => Promise<void>;
  createTask: (task: Omit<Task, 'id' | 'createdAt'>) => Promise<void>;
  updateTaskStatus: (id: number, status: Task['status']) => Promise<void>;
  claimTask: (id: number, owner: string) => Promise<void>;
}

export const useTaskStore = create<TaskStore>((set, get) => ({
  graph: {
    tasks: [],
    ready: [],
    inProgress: [],
    completed: []
  },
  isLoading: false,
  error: null,

  fetchTasks: async () => {
    set({ isLoading: true, error: null });
    try {
      // TODO: Implement actual API call
      set({ isLoading: false });
    } catch (error: unknown) {
      set({ error: (error as Error).message, isLoading: false });
    }
  },

  createTask: async (task) => {
    try {
      const newTask: Task = {
        ...task,
        id: Date.now(),
        createdAt: new Date()
      };
      set((state) => ({
        graph: {
          ...state.graph.graph,
          tasks: [...state.graph.tasks, newTask],
          ready: [...state.graph.ready, newTask]
        }
      }));
    } catch (error) {
      console.error('Failed to create task:', error);
    }
  },

  updateTaskStatus: async (id, status) => {
    try {
      set((state) => ({
        graph: {
          ...state.graph.graph,
          tasks: state.graph.tasks.map((t: Task) =>
            t.id === id ? { ...t, status } : t
          )
        }
      }));
    } catch (error) {
      console.error('Failed to update task:', error);
    }
  },

  claimTask: async (id, owner) => {
    try {
      set((state) => ({
        graph: {
          ...state.graph.graph,
          tasks: state.graph.tasks.map((t: Task) =>
            t.id === id ? { ...t, owner, status: 'in_progress' as Task['status'] } : t
          )
        }
      }));
    } catch (error) {
      console.error('Failed to claim task:', error);
    }
  }
}));
"}

